const cfg = { ...$json };

function text(value, fallback = '') {
  const output = value === undefined || value === null ? '' : String(value).trim();
  return output || fallback;
}

function bool(value) {
  return value === true || value === 'true' || value === '1' || value === 1;
}

function number(value, fallback) {
  const next = Number(value);
  return Number.isFinite(next) ? next : fallback;
}

const action = text(cfg.action, 'list').toLowerCase();
const allowed = ['list', 'account', 'submit', 'poll', 'run'];
if (!allowed.includes(action)) {
  throw new Error('不支持的 libTV action: ' + action);
}

const bridgeBaseUrl = text(cfg.bridge_base_url, 'http://host.docker.internal:8799').replace(/\/+$/, '');
const body = {
  action,
  task_code: text(cfg.task_code),
  task_id: text(cfg.task_id),
  dry_run: bool(cfg.dry_run),
  download: bool(cfg.download),
  model: text(cfg.model, 'star-video2'),
  ratio: text(cfg.ratio, '9:16'),
  duration: text(cfg.duration, '15'),
  resolution: text(cfg.resolution, '720p'),
  enable_sound: text(cfg.enable_sound, 'off'),
  count: text(cfg.count, '1'),
  team_id: text(cfg.team_id),
  node_name: text(cfg.node_name),
  poll_interval: number(cfg.poll_interval, 30),
  max_wait_seconds: number(cfg.max_wait_seconds, 1800),
  timeout: number(cfg.timeout, 600),
  output_dir: text(cfg.output_dir)
};

return {
  json: {
    ...body,
    request_url: bridgeBaseUrl + '/invoke'
  }
};

const response = $json;
const result = response.result || {};
const action = response.action || result.action || 'unknown';

function nextHint() {
  if (!response.ok) return '查看 error / stderr 字段，修复后重跑当前 action。';
  if (action === 'list') return '把 action 改成 submit，并填写 task_code；先保持 dry_run=true 验证。';
  if (action === 'submit') return '提交成功后，把 action 改成 poll 并保持同一个 task_code。';
  if (action === 'poll' && response.result?.status === 'running') return '视频还在生成，稍后再次执行 poll。';
  if (action === 'run') return 'run 已完成提交和轮询；如超时可改 action=poll 继续查。';
  return '流程执行完成。';
}

return {
  json: {
    ok: Boolean(response.ok),
    action,
    returncode: response.returncode,
    duration_seconds: response.duration_seconds,
    count: result.count,
    task_code: result.task_code,
    status: result.status,
    video_url: result.video_url || result.poll?.video_url,
    cover_url: result.cover_url || result.poll?.cover_url,
    result,
    error: response.error,
    stderr: response.stderr,
    next_step: nextHint()
  }
};
